/* stage2.css - Revamped */

/* General Section Styling */
.topic-section {
    margin-bottom: 80px;
    display: flex;
    flex-direction: column;
    gap: 32px;
}

.content-split {
    display: flex;
    gap: 32px;
    background: rgba(0,0,0,0.15);
    border-radius: 24px;
    padding: 32px;
    border: 1px solid var(--glass-border);
}

.content-split.reverse-split {
    flex-direction: row-reverse;
}

@media (max-width: 900px) {
    .content-split, .content-split.reverse-split {
        flex-direction: column;
    }
}

.theory-block, .practice-block {
    flex: 1;
}

.section-heading {
    font-size: 2rem;
    color: var(--neon-purple);
    margin-bottom: 16px;
    text-shadow: 0 0 10px rgba(192, 132, 252, 0.3);
}

.sub-heading {
    font-size: 1.4rem;
    color: #fff;
    margin-bottom: 16px;
}

.desc {
    color: var(--text-muted);
    font-size: 1.1rem;
    line-height: 1.8;
    margin-bottom: 16px;
}

.info-list {
    list-style: none;
    padding: 0;
    margin: 0;
}

.info-list li {
    margin-bottom: 12px;
    padding-left: 24px;
    position: relative;
    color: var(--text-muted);
    line-height: 1.6;
}

.info-list li::before {
    content: "▹";
    color: var(--neon-purple);
    position: absolute;
    left: 0;
    top: 0;
    font-weight: bold;
}

.highlight {
    color: #fff;
    font-weight: 600;
}

/* Simulation Block Common */
.simulation-block {
    padding: 40px;
    border-radius: 28px;
    background: var(--bg-card);
    border: 1px solid var(--glass-border);
    box-shadow: var(--shadow-card);
}

.sim-header {
    text-align: center;
    margin-bottom: 32px;
}

.sim-header h4 {
    color: var(--neon-purple);
    font-size: 1.5rem;
    margin-bottom: 8px;
}

.sim-header p {
    color: var(--text-muted);
}

/* 1. Data Router Simulation */
.data-router-container {
    display: flex;
    flex-direction: column;
    gap: 40px;
}

.incoming-data-stream {
    display: flex;
    justify-content: center;
    gap: 16px;
    flex-wrap: wrap;
    padding: 24px;
    background: rgba(0,0,0,0.3);
    border-radius: 16px;
    border: 1px dashed rgba(192, 132, 252, 0.4);
    min-height: 120px;
}

.data-packet {
    background: linear-gradient(135deg, rgba(255,255,255,0.1), rgba(255,255,255,0.05));
    border: 1px solid var(--glass-border);
    padding: 12px 20px;
    border-radius: 12px;
    cursor: grab;
    display: flex;
    align-items: center;
    gap: 8px;
    font-weight: 600;
    box-shadow: 0 4px 15px rgba(0,0,0,0.2);
    transition: transform 0.2s, box-shadow 0.2s;
    user-select: none;
}

.data-packet:active {
    cursor: grabbing;
    transform: scale(0.95);
}

.data-packet.dragging {
    opacity: 0.5;
    transform: scale(1.05);
}

.data-packet .icon {
    font-size: 1.2rem;
}

.servers-area {
    display: flex;
    gap: 32px;
    justify-content: center;
}

@media (max-width: 768px) {
    .servers-area { flex-direction: column; }
}

.server-node {
    flex: 1;
    background: rgba(0,0,0,0.2);
    border: 2px dashed rgba(255,255,255,0.2);
    border-radius: 20px;
    padding: 32px 24px;
    text-align: center;
    transition: all 0.3s ease;
    position: relative;
    overflow: hidden;
}

.server-node.drag-over {
    border-color: var(--neon-purple);
    background: rgba(192, 132, 252, 0.1);
    transform: translateY(-5px);
}

.server-icon {
    font-size: 3rem;
    margin-bottom: 16px;
    filter: drop-shadow(0 0 10px rgba(255,255,255,0.2));
}

.server-node h5 {
    font-size: 1.2rem;
    color: #fff;
    margin-bottom: 4px;
}

.server-node p {
    color: var(--text-muted);
    font-size: 0.9rem;
    margin-bottom: 24px;
}

.server-capacity {
    height: 8px;
    background: rgba(255,255,255,0.1);
    border-radius: 4px;
    overflow: hidden;
    margin-bottom: 16px;
}

.capacity-fill {
    height: 100%;
    width: 0%;
    background: var(--neon-purple);
    transition: width 0.5s cubic-bezier(0.4, 0, 0.2, 1);
}

.drop-feedback {
    font-weight: bold;
    font-size: 0.9rem;
    min-height: 20px;
    opacity: 0;
    transition: opacity 0.3s;
}

.drop-feedback.show {
    opacity: 1;
}

.feedback-success { color: var(--neon-green); }
.feedback-error { color: var(--neon-red); }

/* Data Routing Animation effect */
@keyframes absorbPacket {
    0% { transform: scale(1); opacity: 1; }
    50% { transform: scale(0.5); opacity: 0.5; filter: blur(5px); }
    100% { transform: scale(0); opacity: 0; }
}

.packet-absorbed {
    animation: absorbPacket 0.5s forwards;
}

/* 2. Data Pipeline */
.pipeline-container {
    display: flex;
    flex-direction: column;
    gap: 24px;
}

.chart-container {
    height: 300px;
    background: rgba(0,0,0,0.4);
    border-radius: 16px;
    border: 1px solid var(--glass-border);
    position: relative;
    overflow: hidden;
    display: flex;
    align-items: center;
    justify-content: center;
}

.data-point {
    position: absolute;
    width: 8px;
    height: 8px;
    border-radius: 50%;
    background: var(--neon-purple);
    transition: all 1s cubic-bezier(0.4, 0, 0.2, 1);
    box-shadow: 0 0 5px var(--neon-purple);
}

.data-point.outlier {
    background: var(--neon-red);
    box-shadow: 0 0 5px var(--neon-red);
    width: 12px;
    height: 12px;
}

.data-point.missing {
    background: rgba(255,255,255,0.2);
    box-shadow: none;
    border: 1px dashed rgba(255,255,255,0.5);
}

.pipeline-controls {
    display: flex;
    justify-content: center;
    gap: 16px;
    flex-wrap: wrap;
}

.pipeline-btn {
    padding: 12px 24px;
    background: rgba(255,255,255,0.05);
    border: 1px solid var(--glass-border);
    color: var(--text-muted);
    border-radius: 50px;
    cursor: pointer;
    font-weight: 600;
    transition: all 0.3s;
    display: flex;
    align-items: center;
    gap: 8px;
}

.pipeline-btn.active-step {
    border-color: var(--neon-purple);
    color: #fff;
    background: rgba(192, 132, 252, 0.1);
    box-shadow: 0 0 15px rgba(192, 132, 252, 0.2);
}

.pipeline-btn.active-step:hover {
    background: var(--neon-purple);
    transform: translateY(-2px);
}

.pipeline-btn.disabled-step {
    opacity: 0.5;
    cursor: not-allowed;
}

.pipeline-btn.completed {
    background: rgba(52, 211, 153, 0.1);
    border-color: var(--neon-green);
    color: var(--neon-green);
}

.pipeline-status {
    background: rgba(0,0,0,0.2);
    padding: 16px;
    border-radius: 12px;
}

.status-indicator {
    font-weight: bold;
    margin-bottom: 8px;
    color: #fff;
}

#pipeline-progress {
    color: var(--neon-purple);
}

.progress-bar {
    height: 12px;
    background: rgba(255,255,255,0.1);
    border-radius: 6px;
    overflow: hidden;
}

.progress-fill {
    height: 100%;
    background: linear-gradient(90deg, var(--neon-purple), var(--neon-green));
    transition: width 1s ease;
}

/* 3. Sentiment Labeling */
.labeling-app {
    max-width: 600px;
    margin: 0 auto;
    background: rgba(0,0,0,0.2);
    border-radius: 20px;
    padding: 32px;
    border: 1px solid var(--glass-border);
}

.review-card {
    background: rgba(255,255,255,0.05);
    padding: 24px;
    border-radius: 12px;
    margin-bottom: 24px;
    border-left: 4px solid var(--neon-purple);
}

.review-header {
    display: flex;
    justify-content: space-between;
    font-size: 0.85rem;
    color: var(--text-muted);
    margin-bottom: 12px;
}

.review-body {
    font-size: 1.2rem;
    line-height: 1.6;
    color: #fff;
    font-style: italic;
}

.label-actions {
    display: flex;
    gap: 16px;
    justify-content: center;
    margin-bottom: 40px;
}

.sentiment-btn {
    padding: 12px 24px;
    border-radius: 50px;
    border: none;
    font-weight: bold;
    cursor: pointer;
    transition: all 0.2s;
    font-size: 1rem;
}

.btn-positive { background: rgba(52, 211, 153, 0.2); color: var(--neon-green); border: 1px solid var(--neon-green); }
.btn-neutral { background: rgba(156, 163, 175, 0.2); color: #fff; border: 1px solid #9ca3af; }
.btn-negative { background: rgba(248, 113, 113, 0.2); color: var(--neon-red); border: 1px solid var(--neon-red); }

.sentiment-btn:hover {
    transform: translateY(-3px);
    box-shadow: 0 5px 15px rgba(0,0,0,0.3);
}

.btn-positive:hover { background: var(--neon-green); color: #000; }
.btn-neutral:hover { background: #9ca3af; color: #000; }
.btn-negative:hover { background: var(--neon-red); color: #fff; }

.model-learning-view {
    background: rgba(0,0,0,0.3);
    padding: 20px;
    border-radius: 12px;
}

.model-learning-view h5 {
    color: #fff;
    margin-bottom: 4px;
}

.model-note {
    font-size: 0.85rem;
    color: var(--text-muted);
    margin-bottom: 16px;
}

.prob-row {
    display: flex;
    align-items: center;
    gap: 12px;
    margin-bottom: 12px;
    font-size: 0.9rem;
}

.prob-row > span:first-child {
    width: 60px;
    color: #ccc;
}

.prob-bar-bg {
    flex: 1;
    height: 10px;
    background: rgba(255,255,255,0.1);
    border-radius: 5px;
    overflow: hidden;
}

.prob-bar-fill {
    height: 100%;
    transition: width 0.5s cubic-bezier(0.4, 0, 0.2, 1);
}

.fill-pos { background: var(--neon-green); }
.fill-neu { background: #9ca3af; }
.fill-neg { background: var(--neon-red); }

.prob-val {
    width: 40px;
    text-align: right;
    font-weight: bold;
    color: #fff;
}

/* 4. Bias Dashboard */
.bias-dashboard {
    display: flex;
    flex-direction: column;
    gap: 32px;
}

.bias-metrics {
    display: flex;
    gap: 24px;
    justify-content: center;
}

.metric-card {
    background: rgba(0,0,0,0.3);
    border: 1px solid var(--glass-border);
    padding: 16px 32px;
    border-radius: 16px;
    text-align: center;
    display: flex;
    flex-direction: column;
    gap: 8px;
    min-width: 200px;
}

.metric-title {
    color: var(--text-muted);
    font-size: 0.9rem;
    text-transform: uppercase;
    letter-spacing: 1px;
}

.metric-value {
    font-size: 2rem;
    font-weight: 800;
    transition: color 0.5s;
}

.distribution-chart {
    display: flex;
    justify-content: center;
    gap: 40px;
    align-items: flex-end;
    height: 250px;
    padding-bottom: 20px;
    border-bottom: 2px solid rgba(255,255,255,0.1);
}

.dist-bar-group {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 12px;
}

.dist-bar-wrapper {
    width: 60px;
    height: 150px;
    background: rgba(255,255,255,0.05);
    border-radius: 8px 8px 0 0;
    position: relative;
    display: flex;
    align-items: flex-end;
}

.dist-bar {
    width: 100%;
    border-radius: 8px 8px 0 0;
    transition: height 0.4s cubic-bezier(0.4, 0, 0.2, 1), background-color 0.4s;
}

.bar-male { background: linear-gradient(0deg, #3b82f6, #60a5fa); }
.bar-female { background: linear-gradient(0deg, #ec4899, #f472b6); }
.bar-child { background: linear-gradient(0deg, #eab308, #fde047); }

.dist-label {
    font-weight: 600;
    color: #fff;
}

.dist-controls {
    display: flex;
    gap: 8px;
}

.dist-controls button {
    width: 32px;
    height: 32px;
    border-radius: 50%;
    border: none;
    background: rgba(255,255,255,0.1);
    color: #fff;
    font-size: 1.2rem;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background 0.2s;
}

.dist-controls button:hover {
    background: var(--neon-purple);
}

.dist-controls button:active {
    transform: scale(0.9);
}

/* Next stage btn */
.purple-btn {
    display: inline-flex;
    align-items: center;
    padding: 16px 32px;
    background: rgba(192, 132, 252, 0.1);
    border: 1px solid var(--neon-purple);
    color: var(--neon-purple);
    border-radius: 50px;
    font-weight: 700;
    font-size: 1.1rem;
    text-decoration: none;
    transition: all 0.3s ease;
}
.purple-btn:hover {
    background: var(--neon-purple);
    color: #fff;
    box-shadow: 0 0 20px rgba(192, 132, 252, 0.4);
    transform: translateY(-2px);
}

// stage2.js - Revamped

document.addEventListener('DOMContentLoaded', () => {

    /* --- 1. DATA ROUTER (Drag & Drop) --- */
    const packets = document.querySelectorAll('.data-packet');
    const servers = document.querySelectorAll('.server-node');
    let structuredCount = 0;
    let unstructuredCount = 0;

    packets.forEach(packet => {
        packet.addEventListener('dragstart', (e) => {
            packet.classList.add('dragging');
        });

        // Touch support for drag and drop
        packet.addEventListener('touchstart', (e) => {
            packet.classList.add('dragging');
        }, {passive: true});

        packet.addEventListener('touchmove', (e) => {
            if (!packet.classList.contains('dragging')) return;
            e.preventDefault();
            const touch = e.targetTouches[0];
            packet.style.position = 'absolute';
            packet.style.left = touch.pageX + 'px';
            packet.style.top = touch.pageY + 'px';
        }, {passive: false});

        packet.addEventListener('touchend', (e) => {
            packet.classList.remove('dragging');
            packet.style.position = 'static';

            const touch = e.changedTouches[0];
            const target = document.elementFromPoint(touch.clientX, touch.clientY);
            if(target) {
                const server = target.closest('.server-node');
                if(server) {
                    processDrop(server, packet);
                }
            }
        });

        packet.addEventListener('dragend', () => {
            packet.classList.remove('dragging');
        });
    });

    servers.forEach(server => {
        server.addEventListener('dragover', (e) => {
            e.preventDefault();
            server.classList.add('drag-over');
        });
        server.addEventListener('dragleave', () => {
            server.classList.remove('drag-over');
        });
        server.addEventListener('drop', (e) => {
            e.preventDefault();
            server.classList.remove('drag-over');
            const dragging = document.querySelector('.dragging');
            if(dragging) {
                processDrop(server, dragging);
            }
        });
    });

    function processDrop(server, packet) {
        const expectedType = server.getAttribute('data-accept');
        const packetType = packet.getAttribute('data-type');
        const feedback = server.querySelector('.drop-feedback');

        if (expectedType === packetType) {
            // Correct
            feedback.innerText = '✅ Başarılı Aktarım';
            feedback.className = 'drop-feedback show feedback-success';
            packet.classList.add('packet-absorbed');

            setTimeout(() => {
                packet.style.display = 'none';
            }, 500);

            // Update Capacity
            if(packetType === 'structured') {
                structuredCount++;
                document.getElementById('cap-struct').style.width = (structuredCount * 50) + '%';
            } else {
                unstructuredCount++;
                document.getElementById('cap-unstruct').style.width = (unstructuredCount * 33.3) + '%';
            }

            setTimeout(() => {
                feedback.classList.remove('show');
            }, 2000);

        } else {
            // Wrong
            feedback.innerText = '❌ Yanlış Format!';
            feedback.className = 'drop-feedback show feedback-error';
            server.style.borderColor = 'var(--neon-red)';
            setTimeout(() => {
                server.style.borderColor = '';
                feedback.classList.remove('show');
            }, 1500);
        }
    }


    /* --- 2. DATA PIPELINE --- */
    const chartContainer = document.getElementById('scatter-chart-container');
    const btnOutlier = document.getElementById('btn-remove-outliers');
    const btnImpute = document.getElementById('btn-impute-missing');
    const btnNormalize = document.getElementById('btn-normalize');
    const pipelineProgress = document.getElementById('pipeline-progress');
    const pipelineBar = document.getElementById('pipeline-bar');

    let points = [];
    const numPoints = 50;

    // Generate random points
    function generatePoints() {
        for(let i=0; i<numPoints; i++) {
            const pt = document.createElement('div');
            pt.className = 'data-point';

            // Random positions 10% to 90%
            const x = 10 + Math.random() * 80;
            const y = 10 + Math.random() * 80;

            pt.style.left = x + '%';
            pt.style.top = y + '%';

            // Make some outliers
            if(i < 5) {
                pt.classList.add('outlier');
                pt.style.left = (Math.random() < 0.5 ? 5 : 95) + '%';
                pt.style.top = (Math.random() < 0.5 ? 5 : 95) + '%';
            }
            // Make some missing
            else if(i > 40) {
                pt.classList.add('missing');
                // scatter them around
            }

            chartContainer.appendChild(pt);
            points.push({ el: pt, isOutlier: i<5, isMissing: i>40, originX: x, originY: y });
        }
    }
    generatePoints();

    function updateProgress(pct) {
        pipelineProgress.innerText = pct + '%';
        pipelineBar.style.width = pct + '%';
        if(pct === 100) {
            pipelineProgress.style.color = 'var(--neon-green)';
        }
    }

    btnOutlier.addEventListener('click', () => {
        if(!btnOutlier.classList.contains('active-step')) return;

        points.forEach(p => {
            if(p.isOutlier) {
                p.el.style.opacity = '0';
                p.el.style.transform = 'scale(0)';
            }
        });

        btnOutlier.classList.remove('active-step');
        btnOutlier.classList.add('completed');
        btnOutlier.innerHTML = '<span class="btn-icon">✅</span> Aykırı Değerler Temizlendi';

        btnImpute.classList.remove('disabled-step');
        btnImpute.classList.add('active-step');
        updateProgress(33);
    });

    btnImpute.addEventListener('click', () => {
        if(!btnImpute.classList.contains('active-step')) return;

        points.forEach(p => {
            if(p.isMissing) {
                p.el.classList.remove('missing');
                // Move them slightly to simulate finding their place
                p.el.style.left = (20 + Math.random() * 60) + '%';
                p.el.style.top = (20 + Math.random() * 60) + '%';
            }
        });

        btnImpute.classList.remove('active-step');
        btnImpute.classList.add('completed');
        btnImpute.innerHTML = '<span class="btn-icon">✅</span> Veriler Dolduruldu';

        btnNormalize.classList.remove('disabled-step');
        btnNormalize.classList.add('active-step');
        updateProgress(66);
    });

    btnNormalize.addEventListener('click', () => {
        if(!btnNormalize.classList.contains('active-step')) return;

        points.forEach(p => {
            if(!p.isOutlier) {
                // Squeeze into a tight, neat cluster in the center (40-60%)
                const nx = 40 + Math.random() * 20;
                const ny = 40 + Math.random() * 20;
                p.el.style.left = nx + '%';
                p.el.style.top = ny + '%';
            }
        });

        btnNormalize.classList.remove('active-step');
        btnNormalize.classList.add('completed');
        btnNormalize.innerHTML = '<span class="btn-icon">✅</span> Veri Normalize Edildi';
        updateProgress(100);
    });


    /* --- 3. SENTIMENT LABELING --- */
    const sentimentBtns = document.querySelectorAll('.sentiment-btn');
    const barPos = document.getElementById('prob-pos');
    const barNeu = document.getElementById('prob-neu');
    const barNeg = document.getElementById('prob-neg');
    const valPos = document.getElementById('val-pos');
    const valNeu = document.getElementById('val-neu');
    const valNeg = document.getElementById('val-neg');

    const reviewText = document.getElementById('review-text');
    const ticketId = document.getElementById('ticket-id');
    const ticketUser = document.getElementById('ticket-user');

    const reviews = [
        { id: "#8943", user: "Z. Demir", text: "Ürün elime hızlı ulaştı fakat paketleme özensizdi. Beklentimin altında." },
        { id: "#8944", user: "E. Yıldız", text: "Gerçekten harika bir hizmet! Herkese tavsiye ediyorum, çok teşekkürler." },
        { id: "#8945", user: "M. Can", text: "Kargo süreci normaldi. Ürün iş görüyor. Fiyat performans ürünü diyebilirim." }
    ];
    let reviewIndex = 0;

    function updateProbabilities(pos, neu, neg) {
        barPos.style.width = pos + '%';
        barNeu.style.width = neu + '%';
        barNeg.style.width = neg + '%';

        valPos.innerText = pos + '%';
        valNeu.innerText = neu + '%';
        valNeg.innerText = neg + '%';
    }

    sentimentBtns.forEach(btn => {
        btn.addEventListener('click', () => {
            const sentiment = btn.getAttribute('data-sentiment');

            if(sentiment === 'positive') updateProbabilities(88, 8, 4);
            if(sentiment === 'neutral') updateProbabilities(15, 75, 10);
            if(sentiment === 'negative') updateProbabilities(5, 10, 85);

            // Load next review after a short delay
            setTimeout(() => {
                if(reviewIndex < reviews.length) {
                    reviewText.style.opacity = 0;
                    setTimeout(() => {
                        ticketId.innerText = `Ticket ${reviews[reviewIndex].id}`;
                        ticketUser.innerText = `Kullanıcı: ${reviews[reviewIndex].user}`;
                        reviewText.innerText = `"${reviews[reviewIndex].text}"`;
                        reviewText.style.opacity = 1;

                        // Reset probabilities slightly to simulate thinking on new text
                        updateProbabilities(33, 33, 34);
                        reviewIndex++;
                    }, 300);
                } else {
                    reviewText.innerText = "Tebrikler! Günlük etiketleme hedefinize ulaştınız. Model başarıyla güncellendi.";
                    document.getElementById('label-actions').style.display = 'none';
                }
            }, 1000);
        });
    });


    /* --- 4. BIAS DASHBOARD --- */
    const biasData = {
        male: 90,
        female: 30,
        child: 15
    };

    const bars = {
        male: document.getElementById('bar-male'),
        female: document.getElementById('bar-female'),
        child: document.getElementById('bar-child')
    };

    const scoreDisplay = document.getElementById('fairness-score');
    const warningDisplay = document.getElementById('bias-warning');
    const btnDistControls = document.querySelectorAll('.dist-controls button');

    function calculateFairness() {
        const vals = Object.values(biasData);
        const max = Math.max(...vals);
        const min = Math.min(...vals);
        const avg = vals.reduce((a,b)=>a+b, 0) / vals.length;

        // Simple variance metric mapped to 0-100
        let variance = vals.reduce((a, b) => a + Math.pow(b - avg, 2), 0) / vals.length;

        let score = 100 - Math.min(100, Math.sqrt(variance) * 2);
        score = Math.round(score);

        if(score > 90) {
            scoreDisplay.style.color = 'var(--neon-green)';
            warningDisplay.style.color = 'var(--neon-green)';
            warningDisplay.innerText = 'Dengeli Model!';
            // Animate bars to glow
            Object.values(bars).forEach(b => b.style.boxShadow = '0 0 15px rgba(52, 211, 153, 0.5)');
        } else if (score > 60) {
            scoreDisplay.style.color = 'var(--text-main)';
            warningDisplay.style.color = 'var(--text-main)';
            warningDisplay.innerText = 'Orta Risk';
            Object.values(bars).forEach(b => b.style.boxShadow = 'none');
        } else {
            scoreDisplay.style.color = 'var(--neon-red)';
            warningDisplay.style.color = 'var(--neon-red)';
            warningDisplay.innerText = 'Yüksek Risk (Biased)';
            Object.values(bars).forEach(b => b.style.boxShadow = 'none');
        }

        scoreDisplay.innerText = score + '%';
    }

    function renderBars() {
        bars.male.style.height = biasData.male + '%';
        bars.female.style.height = biasData.female + '%';
        bars.child.style.height = biasData.child + '%';
        calculateFairness();
    }

    btnDistControls.forEach(btn => {
        btn.addEventListener('click', () => {
            const cls = btn.getAttribute('data-class');
            const action = btn.getAttribute('data-action');

            if(action === 'increase') {
                biasData[cls] = Math.min(100, biasData[cls] + 10);
            } else {
                biasData[cls] = Math.max(10, biasData[cls] - 10);
            }

            renderBars();
        });
    });

    renderBars();

});

