// stage3.js

document.addEventListener('DOMContentLoaded', () => {

    /* --- 1. ALGORITHM SELECTION (Drag & Drop) --- */
    const scenarios = document.querySelectorAll('.scenario-card');
    const algoBoxes = document.querySelectorAll('.algo-box');

    scenarios.forEach(card => {
        card.addEventListener('dragstart', (e) => {
            card.classList.add('dragging');
            e.dataTransfer.setData('text/plain', card.getAttribute('data-type'));
        });

        card.addEventListener('dragend', () => {
            card.classList.remove('dragging');
        });
    });

    algoBoxes.forEach(box => {
        box.addEventListener('dragover', (e) => {
            e.preventDefault();
            box.classList.add('drag-over');
        });

        box.addEventListener('dragleave', () => {
            box.classList.remove('drag-over');
        });

        box.addEventListener('drop', (e) => {
            e.preventDefault();
            box.classList.remove('drag-over');
            const dragging = document.querySelector('.dragging');
            if (dragging) {
                const expectedType = box.getAttribute('data-accept');
                const draggedType = dragging.getAttribute('data-type');

                if (expectedType === draggedType) {
                    box.appendChild(dragging);
                    box.style.borderColor = 'var(--neon-green)';
                    setTimeout(() => box.style.borderColor = '', 500);
                } else {
                    box.style.borderColor = 'var(--neon-red)';
                    dragging.style.transform = 'translateX(10px)';
                    setTimeout(() => {
                        dragging.style.transform = '';
                        box.style.borderColor = '';
                    }, 300);
                }
            }
        });
    });


    /* --- 2. LEARNING SIMULATOR (Supervised vs Unsupervised) --- */
    const btnSupervised = document.getElementById('btn-supervised');
    const btnUnsupervised = document.getElementById('btn-unsupervised');
    const btnTrain = document.getElementById('btn-train-model');
    const learningCanvas = document.getElementById('learning-canvas');
    const learningTitle = document.getElementById('learning-title');
    const learningDesc = document.getElementById('learning-desc');

    let learningMode = 'supervised'; // 'supervised' or 'unsupervised'
    let isTrained = false;
    let points = [];

    function initLearningCanvas() {
        learningCanvas.innerHTML = '';
        points = [];
        isTrained = false;

        // Generate points
        for(let i=0; i<40; i++) {
            const pt = document.createElement('div');
            pt.className = 'sim-point';

            let x, y, cls;
            if(Math.random() > 0.5) {
                x = 10 + Math.random() * 40;
                y = 10 + Math.random() * 80;
                cls = 'class-a'; // Red group
            } else {
                x = 50 + Math.random() * 40;
                y = 10 + Math.random() * 80;
                cls = 'class-b'; // Blue group
            }

            pt.style.left = x + '%';
            pt.style.top = y + '%';

            if(learningMode === 'supervised') {
                pt.classList.add(cls);
            } else {
                pt.classList.add('unassigned');
            }

            // Save metadata
            points.push({ el: pt, x: x, y: y, trueClass: cls });
            learningCanvas.appendChild(pt);
        }

        // Add boundary line div (hidden initially)
        const boundary = document.createElement('div');
        boundary.className = 'decision-boundary';
        boundary.id = 'decision-boundary';
        boundary.style.width = '4px';
        boundary.style.height = '0%';
        boundary.style.left = '50%';
        boundary.style.top = '0%';
        learningCanvas.appendChild(boundary);
    }

    btnSupervised.addEventListener('click', () => {
        learningMode = 'supervised';
        btnSupervised.classList.add('active');
        btnUnsupervised.classList.remove('active');
        learningTitle.innerText = "Sınıflandırma (Classification)";
        learningDesc.innerText = "Modelin amacı: Kırmızı ve Mavi noktaları (çünkü etiketleri belli) birbirinden ayıran en doğru çizgiyi (karar sınırı) bulmak.";
        initLearningCanvas();
    });

    btnUnsupervised.addEventListener('click', () => {
        learningMode = 'unsupervised';
        btnUnsupervised.classList.add('active');
        btnSupervised.classList.remove('active');
        learningTitle.innerText = "Kümeleme (Clustering)";
        learningDesc.innerText = "Modelin amacı: Renkleri (etiketleri) bilinmeyen bu noktaları, birbirlerine olan yakınlıklarına göre 2 farklı gruba ayırmak.";
        initLearningCanvas();
    });

    btnTrain.addEventListener('click', () => {
        if(isTrained) return;
        isTrained = true;

        if(learningMode === 'supervised') {
            const boundary = document.getElementById('decision-boundary');
            boundary.style.opacity = '1';
            boundary.style.height = '100%';
        } else {
            // Simulate clustering animation
            points.forEach(p => {
                p.el.classList.remove('unassigned');
                if(p.x < 50) {
                    p.el.classList.add('cluster-1'); // Purple
                } else {
                    p.el.classList.add('cluster-2'); // Green
                }
            });
        }
    });

    // Init first time
    initLearningCanvas();


    /* --- 3. OVERFITTING SIMULATOR --- */
    const complexitySlider = document.getElementById('complexity-slider');
    const compValText = document.getElementById('complexity-val');
    const trainBar = document.getElementById('train-error-bar');
    const testBar = document.getElementById('test-error-bar');
    const btnAddTest = document.getElementById('btn-add-test-data');
    const ofCanvas = document.getElementById('overfit-canvas');

    // Data points: x (10 to 390), y (10 to 290)
    // A subtle sine wave with noise
    const trainData = [];
    for(let i=20; i<=380; i+=30) {
        let baseY = 150 + Math.sin(i / 50) * 80;
        let noiseY = baseY + (Math.random() - 0.5) * 40;
        trainData.push({x: i, y: Math.max(10, Math.min(290, noiseY))});
    }

    // Generate test data (closer to true sine wave)
    const testData = [];
    for(let i=35; i<=365; i+=40) {
        let trueY = 150 + Math.sin(i / 50) * 80;
        testData.push({x: i, y: trueY});
    }

    let testDataVisible = false;

    function drawOverfitting() {
        ofCanvas.innerHTML = '';

        // Draw train points
        trainData.forEach(p => {
            const circle = document.createElementNS('http://www.w3.org/2000/svg', 'circle');
            circle.setAttribute('cx', p.x);
            circle.setAttribute('cy', p.y);
            circle.setAttribute('r', 5);
            circle.setAttribute('class', 'of-point-train');
            ofCanvas.appendChild(circle);
        });

        // Draw test points
        testData.forEach(p => {
            const circle = document.createElementNS('http://www.w3.org/2000/svg', 'circle');
            circle.setAttribute('cx', p.x);
            circle.setAttribute('cy', p.y);
            circle.setAttribute('r', 5);
            circle.setAttribute('class', testDataVisible ? 'of-point-test show' : 'of-point-test');
            ofCanvas.appendChild(circle);
        });

        // Draw line based on complexity
        const line = document.createElementNS('http://www.w3.org/2000/svg', 'path');
        line.setAttribute('class', 'of-line');

        const val = parseInt(complexitySlider.value);
        let pathStr = '';

        if(val === 1) {
            // Underfitting: straight line
            compValText.innerText = 'Düşük (Underfitting)';
            compValText.style.color = 'var(--text-main)';
            pathStr = `M 20 150 L 380 150`;
            trainBar.style.width = '70%';
            testBar.style.width = '75%';
        } else if(val === 2) {
            // Optimal: smooth sine wave
            compValText.innerText = 'Optimum (İdeal)';
            compValText.style.color = 'var(--neon-green)';
            pathStr = `M 20 ${150 + Math.sin(20/50)*80}`;
            for(let i=30; i<=380; i+=10) {
                pathStr += ` L ${i} ${150 + Math.sin(i/50)*80}`;
            }
            trainBar.style.width = '20%';
            testBar.style.width = '25%';
        } else if(val === 3) {
            // Overfitting: jagged line through train points
            compValText.innerText = 'Yüksek (Overfitting)';
            compValText.style.color = 'var(--neon-red)';
            pathStr = `M ${trainData[0].x} ${trainData[0].y}`;
            for(let i=1; i<trainData.length; i++) {
                pathStr += ` L ${trainData[i].x} ${trainData[i].y}`;
            }
            trainBar.style.width = '5%'; // Almost zero training error
            testBar.style.width = '90%'; // Massive testing error
        }

        line.setAttribute('d', pathStr);
        ofCanvas.appendChild(line);
    }

    complexitySlider.addEventListener('input', drawOverfitting);

    btnAddTest.addEventListener('click', () => {
        testDataVisible = true;
        btnAddTest.style.display = 'none'; // hide after showing
        drawOverfitting();
    });

    drawOverfitting(); // Init


    /* --- 4. NO-CODE SIMULATOR --- */
    const paletteItems = document.querySelectorAll('.palette-item');
    const nodeCanvas = document.getElementById('node-canvas');
    const svgLines = document.getElementById('connection-lines');
    const btnRun = document.getElementById('btn-run-pipeline');

    let nodesInCanvas = [];
    let isDragging = false;
    let draggedNode = null;
    let offsetX, offsetY;

    const positions = [
        {x: 100, y: 100},
        {x: 280, y: 150},
        {x: 460, y: 100},
        {x: 640, y: 200}
    ];
    let posIndex = 0;

    paletteItems.forEach(item => {
        item.addEventListener('click', () => {
            if(item.classList.contains('used')) return;

            const nodeId = item.getAttribute('data-node');
            const text = item.innerText;

            createNode(nodeId, text);

            item.classList.add('used');
            checkPipelineComplete();
        });
    });

    function createNode(id, text) {
        const node = document.createElement('div');
        node.className = 'node-box';
        node.setAttribute('data-id', id);
        node.innerText = text;

        const connector = document.createElement('div');
        connector.className = 'node-connector';
        node.appendChild(connector);

        // Positioning
        let pos = positions[Math.min(posIndex, positions.length-1)];
        node.style.left = pos.x + 'px';
        node.style.top = pos.y + 'px';
        posIndex++;

        nodeCanvas.appendChild(node);
        nodesInCanvas.push({ id: id, el: node });

        // Draggable logic
        node.addEventListener('mousedown', (e) => {
            if(e.target.classList.contains('node-connector')) return;
            isDragging = true;
            draggedNode = node;
            const rect = node.getBoundingClientRect();
            const canvasRect = nodeCanvas.getBoundingClientRect();
            offsetX = e.clientX - rect.left;
            offsetY = e.clientY - rect.top;
        });

        drawLines();
    }

    document.addEventListener('mousemove', (e) => {
        if(!isDragging || !draggedNode) return;
        const canvasRect = nodeCanvas.getBoundingClientRect();
        let newX = e.clientX - canvasRect.left - offsetX + (draggedNode.offsetWidth/2);
        let newY = e.clientY - canvasRect.top - offsetY + (draggedNode.offsetHeight/2);

        draggedNode.style.left = newX + 'px';
        draggedNode.style.top = newY + 'px';
        drawLines();
    });

    document.addEventListener('mouseup', () => {
        isDragging = false;
        draggedNode = null;
    });

    function drawLines() {
        svgLines.innerHTML = '';
        if(nodesInCanvas.length < 2) return;

        for(let i=0; i<nodesInCanvas.length - 1; i++) {
            const startNode = nodesInCanvas[i].el;
            const endNode = nodesInCanvas[i+1].el;

            const startX = parseFloat(startNode.style.left) + (startNode.offsetWidth/2);
            const startY = parseFloat(startNode.style.top);

            const endX = parseFloat(endNode.style.left) - (endNode.offsetWidth/2);
            const endY = parseFloat(endNode.style.top);

            const path = document.createElementNS('http://www.w3.org/2000/svg', 'path');
            // Bezier curve
            const d = `M ${startX} ${startY} C ${startX + 50} ${startY}, ${endX - 50} ${endY}, ${endX} ${endY}`;
            path.setAttribute('d', d);
            path.setAttribute('fill', 'none');
            path.setAttribute('stroke', 'var(--neon-purple)');
            path.setAttribute('stroke-width', '3');
            svgLines.appendChild(path);
        }
    }

    function checkPipelineComplete() {
        if(nodesInCanvas.length === 4) {
            btnRun.removeAttribute('disabled');
        }
    }

    btnRun.addEventListener('click', () => {
        btnRun.innerText = 'Çalışıyor...';

        let paths = svgLines.querySelectorAll('path');
        paths.forEach(p => p.style.stroke = 'var(--neon-green)');

        nodesInCanvas.forEach(n => {
            n.el.style.borderColor = 'var(--neon-green)';
            n.el.style.boxShadow = '0 0 15px rgba(52, 211, 153, 0.4)';
        });

        setTimeout(() => {
            btnRun.innerText = 'Başarılı: Model Eğitildi ✅';
            btnRun.style.background = 'var(--bg-card)';
            btnRun.style.color = 'var(--neon-green)';
            btnRun.style.border = '1px solid var(--neon-green)';
        }, 1500);
    });

});

