// stage4.js

document.addEventListener('DOMContentLoaded', () => {

    /* --- 1. Confusion Matrix Simulation --- */
    const thresholdSlider = document.getElementById('threshold-slider');
    const thresholdVal = document.getElementById('threshold-val');
    const statAcc = document.getElementById('stat-acc');

    const cellTn = document.querySelector('#cell-tn .cell-value');
    const cellFp = document.querySelector('#cell-fp .cell-value');
    const cellFn = document.querySelector('#cell-fn .cell-value');
    const cellTp = document.querySelector('#cell-tp .cell-value');

    // Total patients: 1000 (420 healthy, 580 sick)
    const total = 1000;

    function updateMatrix(value) {
        let tn, fp, fn, tp;

        if (value == 1) {
            // Strict (Katı) - FP goes down, FN goes up
            thresholdVal.textContent = "Katı (Az FP)";
            tn = 415; fp = 5;
            fn = 150; tp = 430;
        } else if (value == 2) {
            // Balanced (Dengeli)
            thresholdVal.textContent = "Dengeli";
            tn = 400; fp = 20;
            fn = 40;  tp = 540;
        } else {
            // Sensitive (Hassas) - FN goes down, FP goes up
            thresholdVal.textContent = "Hassas (Az FN)";
            tn = 250; fp = 170;
            fn = 5;   tp = 575;
        }

        // Animate values
        animateValue(cellTn, parseInt(cellTn.innerText), tn, 400);
        animateValue(cellFp, parseInt(cellFp.innerText), fp, 400);
        animateValue(cellFn, parseInt(cellFn.innerText), fn, 400);
        animateValue(cellTp, parseInt(cellTp.innerText), tp, 400);

        // Accuracy = (TP + TN) / Total
